import type { Meta, StoryObj } from '@storybook/react-vite';
import { TabPane } from './TabPane';
import { Tabs } from './Tabs';
import { Text } from '../Text';

const meta = {
  title: 'Components/TabPane',
  component: TabPane,
  tags: ['autodocs'],
  argTypes: {
    name: { control: 'text' },
    label: { control: 'text' },
    disabled: { control: 'boolean' },
    closable: { control: 'boolean' },
    lazy: { control: 'boolean' },
  },
  args: {
    // Required prop; the story renders panes inside Tabs via `render`.
    name: 'one',
  },
} satisfies Meta<typeof TabPane>;

export default meta;
type Story = StoryObj<typeof meta>;

export const InsideTabs: Story = {
  name: 'Inside Tabs',
  render: () => (
    <Tabs defaultValue="one">
      <TabPane name="one" label="First">
        <div style={{ padding: '12px 4px' }}>
          <Text>First pane content.</Text>
        </div>
      </TabPane>
      <TabPane name="two" label="Second">
        <div style={{ padding: '12px 4px' }}>
          <Text>Second pane content.</Text>
        </div>
      </TabPane>
      <TabPane name="three" label="Disabled" disabled>
        <div style={{ padding: '12px 4px' }}>Disabled pane.</div>
      </TabPane>
    </Tabs>
  ),
};

import { forwardRef, type HTMLAttributes, type ReactNode } from 'react';
import { cls, useNamespace } from '../../utils';

export interface TabPaneProps extends Omit<HTMLAttributes<HTMLDivElement>, 'id'> {
  /** Unique identifier for the pane, matched against the active value. */
  name: string;
  /** Tab header label. */
  label?: ReactNode;
  /** Disable selecting this pane. */
  disabled?: boolean;
  /** Allow this specific pane to be closed (overrides the parent `closable`). */
  closable?: boolean;
  /** Only render the pane content once it has been activated. */
  lazy?: boolean;
  children?: ReactNode;
}

/**
 * Configuration carrier for a single tab. `Tabs` reads these props to build the
 * header; when rendered on its own it falls back to a simple tab panel.
 */
export const TabPane = forwardRef<HTMLDivElement, TabPaneProps>(function TabPane(props, ref) {
  const {
    name,
    label,
    disabled = false,
    closable,
    lazy,
    className,
    children,
    ...rest
  } = props;

  // `label`, `disabled`, `closable` and `lazy` are consumed by the parent Tabs.
  void label;
  void disabled;
  void closable;
  void lazy;

  const ns = useNamespace('tab-pane');

  return (
    <div
      ref={ref}
      role="tabpanel"
      data-name={name}
      className={cls(ns.b(), className)}
      {...rest}
    >
      {children}
    </div>
  );
});

import { useState, type ReactNode } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Tabs } from './Tabs';
import { TabPane } from './TabPane';
import { Text } from '../Text';

function Pane({ children }: { children: ReactNode }) {
  return <div style={{ padding: '12px 4px' }}>{children}</div>;
}

const meta = {
  title: 'Components/Tabs',
  component: Tabs,
  tags: ['autodocs'],
  argTypes: {
    type: { control: 'inline-radio', options: ['line', 'card', 'border-card'] },
    tabPosition: { control: 'inline-radio', options: ['top', 'right', 'bottom', 'left'] },
    closable: { control: 'boolean' },
    addable: { control: 'boolean' },
    editable: { control: 'boolean' },
    stretch: { control: 'boolean' },
  },
} satisfies Meta<typeof Tabs>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Line: Story = {
  name: 'Line (default)',
  render: () => {
    const [active, setActive] = useState('overview');
    return (
      <Tabs value={active} onChange={setActive}>
        <TabPane name="overview" label="Overview">
          <Pane>
            <Text>The overview tab summarizes the project at a glance.</Text>
          </Pane>
        </TabPane>
        <TabPane name="activity" label="Activity">
          <Pane>
            <Text>Recent commits, reviews and releases live here.</Text>
          </Pane>
        </TabPane>
        <TabPane name="settings" label="Settings">
          <Pane>
            <Text>Configuration and access controls.</Text>
          </Pane>
        </TabPane>
        <TabPane name="archived" label="Archived" disabled>
          <Pane>Disabled</Pane>
        </TabPane>
      </Tabs>
    );
  },
};

export const Card: Story = {
  name: 'Card type',
  render: () => (
    <Tabs type="card" defaultValue="a">
      <TabPane name="a" label="Drafts">
        <Pane>3 drafts waiting for review.</Pane>
      </TabPane>
      <TabPane name="b" label="Published">
        <Pane>128 published articles.</Pane>
      </TabPane>
      <TabPane name="c" label="Trash">
        <Pane>Items here are deleted after 30 days.</Pane>
      </TabPane>
    </Tabs>
  ),
};

export const BorderCardLeft: Story = {
  name: 'Border card, left position',
  render: () => (
    <Tabs type="border-card" tabPosition="left" defaultValue="profile">
      <TabPane name="profile" label="Profile">
        <Pane>Profile details.</Pane>
      </TabPane>
      <TabPane name="security" label="Security">
        <Pane>Password and 2FA.</Pane>
      </TabPane>
      <TabPane name="billing" label="Billing">
        <Pane>Plans and invoices.</Pane>
      </TabPane>
    </Tabs>
  ),
};

import {
  Children,
  forwardRef,
  type HTMLAttributes,
  isValidElement,
  type KeyboardEvent,
  type ReactElement,
  type ReactNode,
  useRef,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { Icon } from '../Icon';
import { TabPane, type TabPaneProps } from './TabPane';

export type TabsType = 'line' | 'card' | 'border-card';

export type TabPosition = 'top' | 'right' | 'bottom' | 'left';

export interface TabsProps extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange'> {
  /** Active tab name (controlled). */
  value?: string;
  /** Initial active tab name (uncontrolled). */
  defaultValue?: string;
  /** Fired when the active tab changes. */
  onChange?: (name: string) => void;
  /** Visual style of the tabs. */
  type?: TabsType;
  /** Position of the tab header relative to the content. */
  tabPosition?: TabPosition;
  /** Show a close button on every tab. */
  closable?: boolean;
  /** Show an "add tab" button. */
  addable?: boolean;
  /** Shorthand to enable both `addable` and `closable`. */
  editable?: boolean;
  /** Stretch tabs to fill the available width. */
  stretch?: boolean;
  /** Fired when a tab header is clicked (even if already active). */
  onTabClick?: (name: string) => void;
  /** Fired when a tab's close button is clicked. */
  onTabRemove?: (name: string) => void;
  /** Fired when the add button is clicked. */
  onTabAdd?: () => void;
  children?: ReactNode;
}

interface PaneMeta {
  name: string;
  label: ReactNode;
  disabled: boolean;
  closable: boolean;
  lazy: boolean;
  element: ReactElement<TabPaneProps>;
}

function CloseIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path
        fill="currentColor"
        d="M764.288 214.592 512 466.88 259.712 214.592a31.936 31.936 0 0 0-45.12 45.12L466.752 512 214.528 764.224a31.936 31.936 0 1 0 45.12 45.184L512 557.184l252.288 252.288a31.936 31.936 0 0 0 45.12-45.12L557.12 512.064l252.288-252.352a31.936 31.936 0 1 0-45.12-45.184z"
      />
    </svg>
  );
}

function AddIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path
        fill="currentColor"
        d="M480 480V128a32 32 0 0 1 64 0v352h352a32 32 0 1 1 0 64H544v352a32 32 0 1 1-64 0V544H128a32 32 0 0 1 0-64z"
      />
    </svg>
  );
}

function isTabPane(child: ReactNode): child is ReactElement<TabPaneProps> {
  return isValidElement(child) && child.type === TabPane;
}

export const Tabs = forwardRef<HTMLDivElement, TabsProps>(function Tabs(props, ref) {
  const {
    value,
    defaultValue,
    onChange,
    type = 'line',
    tabPosition = 'top',
    closable = false,
    addable = false,
    editable = false,
    stretch = false,
    onTabClick,
    onTabRemove,
    onTabAdd,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('tabs');

  const panes: PaneMeta[] = [];
  Children.forEach(children, (child) => {
    if (!isTabPane(child)) {
      return;
    }
    const p = child.props;
    panes.push({
      name: p.name,
      label: p.label ?? p.name,
      disabled: p.disabled ?? false,
      closable: p.closable ?? false,
      lazy: p.lazy ?? false,
      element: child,
    });
  });

  const firstName = panes[0]?.name ?? '';
  const isControlled = value !== undefined;
  const [internalValue, setInternalValue] = useState<string>(defaultValue ?? firstName);
  const active = isControlled ? value : internalValue;

  // Track which lazy panes have been activated so their content is mounted once.
  const mountedRef = useRef<Set<string>>(new Set());
  if (active) {
    mountedRef.current.add(active);
  }

  const showAdd = addable || editable;
  const allClosable = closable || editable;
  const isVertical = tabPosition === 'left' || tabPosition === 'right';

  // Roving tabindex: exactly one tab is in the focus order. That is the active
  // tab when it is enabled, otherwise the first enabled tab (so keyboard users
  // can still reach the tablist even if the active tab is disabled).
  const activePane = panes.find((pane) => pane.name === active && !pane.disabled);
  const rovingName = activePane?.name ?? panes.find((pane) => !pane.disabled)?.name;

  // Refs to every tab header element, keyed by pane name, for roving focus.
  const tabRefs = useRef<Map<string, HTMLDivElement>>(new Map());

  const selectTab = (name: string, disabled: boolean) => {
    if (disabled) {
      return;
    }
    onTabClick?.(name);
    if (name === active) {
      return;
    }
    if (!isControlled) {
      setInternalValue(name);
    }
    onChange?.(name);
  };

  const removeTab = (name: string) => {
    onTabRemove?.(name);
  };

  // Move focus to (and activate) a tab starting at `index`, skipping disabled
  // tabs in `step` direction and wrapping around. Bails out if all are disabled.
  const focusTabAt = (index: number, step: 1 | -1) => {
    const total = panes.length;
    if (total === 0) {
      return;
    }
    let next = ((index % total) + total) % total;
    for (let i = 0; i < total; i += 1) {
      const candidate = panes[next];
      if (candidate && !candidate.disabled) {
        tabRefs.current.get(candidate.name)?.focus();
        selectTab(candidate.name, candidate.disabled);
        return;
      }
      next = (((next + step) % total) + total) % total;
    }
  };

  const onTabKeyDown = (event: KeyboardEvent<HTMLDivElement>, index: number) => {
    const prevKey = isVertical ? 'ArrowUp' : 'ArrowLeft';
    const nextKey = isVertical ? 'ArrowDown' : 'ArrowRight';
    switch (event.key) {
      case prevKey:
        event.preventDefault();
        focusTabAt(index - 1, -1);
        break;
      case nextKey:
        event.preventDefault();
        focusTabAt(index + 1, 1);
        break;
      case 'Home':
        event.preventDefault();
        focusTabAt(0, 1);
        break;
      case 'End':
        event.preventDefault();
        focusTabAt(panes.length - 1, -1);
        break;
      case 'Enter':
      case ' ':
        event.preventDefault();
        selectTab(panes[index]?.name ?? '', panes[index]?.disabled ?? false);
        break;
      default:
        break;
    }
  };

  const classes = cls(
    ns.b(),
    ns.m(type),
    ns.m(`position-${tabPosition}`),
    ns.is('stretch', stretch),
    className,
  );

  return (
    <div ref={ref} className={classes} {...rest}>
      <div className={ns.e('header')}>
        <div
          className={ns.e('nav')}
          role="tablist"
          aria-orientation={isVertical ? 'vertical' : 'horizontal'}
        >
          {panes.map((pane, index) => {
            const isActive = pane.name === active;
            const paneClosable = type !== 'border-card' && (allClosable || pane.closable);
            return (
              <div
                key={pane.name}
                ref={(el) => {
                  if (el) {
                    tabRefs.current.set(pane.name, el);
                  } else {
                    tabRefs.current.delete(pane.name);
                  }
                }}
                role="tab"
                id={`${ns.b()}-tab-${pane.name}`}
                aria-selected={isActive}
                aria-disabled={pane.disabled || undefined}
                aria-controls={`${ns.b()}-panel-${pane.name}`}
                tabIndex={pane.name === rovingName ? 0 : -1}
                className={cls(
                  ns.e('item'),
                  ns.is('active', isActive),
                  ns.is('disabled', pane.disabled),
                  ns.is('closable', paneClosable),
                )}
                onClick={() => selectTab(pane.name, pane.disabled)}
                onKeyDown={(event) => onTabKeyDown(event, index)}
              >
                <span className={ns.e('label')}>{pane.label}</span>
                {paneClosable && (
                  <button
                    type="button"
                    className={ns.e('close')}
                    aria-label="Close tab"
                    onClick={(event) => {
                      event.stopPropagation();
                      removeTab(pane.name);
                    }}
                    onKeyDown={(event) => {
                      // Keep tab-level arrow/Home/End navigation from firing,
                      // and activate the close control on Enter/Space.
                      if (event.key === 'Enter' || event.key === ' ') {
                        event.preventDefault();
                        event.stopPropagation();
                        removeTab(pane.name);
                      }
                    }}
                  >
                    <Icon aria-hidden="true">
                      <CloseIcon />
                    </Icon>
                  </button>
                )}
              </div>
            );
          })}
          {type === 'line' && (
            <span className={ns.e('active-bar')} aria-hidden="true" />
          )}
        </div>
        {showAdd && (
          <button
            type="button"
            className={ns.e('add')}
            aria-label="Add tab"
            onClick={() => onTabAdd?.()}
          >
            <Icon>
              <AddIcon />
            </Icon>
          </button>
        )}
      </div>
      <div className={ns.e('content')}>
        {panes.map((pane) => {
          const isActive = pane.name === active;
          if (pane.lazy && !isActive && !mountedRef.current.has(pane.name)) {
            return null;
          }
          return (
            <div
              key={pane.name}
              role="tabpanel"
              id={`${ns.b()}-panel-${pane.name}`}
              aria-labelledby={`${ns.b()}-tab-${pane.name}`}
              hidden={!isActive}
              className={cls(ns.e('pane'), ns.is('active', isActive))}
            >
              {pane.element.props.children}
            </div>
          );
        })}
      </div>
    </div>
  );
});

.ec-tabs {
  --ec-tabs-header-height: 40px;
  --ec-tabs-active-color: var(--ec-color-primary);
  --ec-tabs-item-color: var(--ec-text-color-primary);
  --ec-tabs-item-hover-color: var(--ec-color-primary);
  --ec-tabs-item-disabled-color: var(--ec-disabled-text-color);
  --ec-tabs-border-color: var(--ec-border-color-light);

  box-sizing: border-box;
  font-family: var(--ec-font-family);
  font-size: var(--ec-font-size-base);
  color: var(--ec-text-color-primary);
}

.ec-tabs *,
.ec-tabs *::before,
.ec-tabs *::after {
  box-sizing: border-box;
}

/* ---- Header ---- */
.ec-tabs__header {
  display: flex;
  align-items: center;
  position: relative;
  margin: 0 0 15px;
}

.ec-tabs__nav {
  display: flex;
  position: relative;
  flex: 1;
  align-items: center;
}

.ec-tabs__item {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  height: var(--ec-tabs-header-height);
  padding: 0 20px;
  font-size: var(--ec-font-size-base);
  font-weight: var(--ec-font-weight-primary);
  line-height: var(--ec-tabs-header-height);
  color: var(--ec-tabs-item-color);
  white-space: nowrap;
  list-style: none;
  cursor: pointer;
  outline: none;
  user-select: none;
  transition: var(--ec-transition-color);
}

.ec-tabs__item:hover {
  color: var(--ec-tabs-item-hover-color);
}

.ec-tabs__item:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: -2px;
  border-radius: var(--ec-border-radius-small);
}

.ec-tabs__item.is-active {
  color: var(--ec-tabs-active-color);
}

.ec-tabs__item.is-disabled {
  color: var(--ec-tabs-item-disabled-color);
  cursor: not-allowed;
}

.ec-tabs__item.is-disabled:hover {
  color: var(--ec-tabs-item-disabled-color);
}

.ec-tabs__label {
  display: inline-flex;
  align-items: center;
}

.ec-tabs__close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 14px;
  height: 14px;
  padding: 0;
  font-size: 12px;
  color: inherit;
  background: none;
  border: none;
  border-radius: 50%;
  cursor: pointer;
  transition: var(--ec-transition-all);
}

.ec-tabs__close:hover {
  color: var(--ec-color-white);
  background-color: var(--ec-text-color-placeholder);
}

.ec-tabs__close:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

.ec-tabs__add {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  margin-left: 8px;
  padding: 0;
  font-size: 14px;
  color: var(--ec-tabs-item-color);
  background: none;
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
  border-radius: var(--ec-border-radius-base);
  cursor: pointer;
  transition: var(--ec-transition-all);
}

.ec-tabs__add:hover {
  color: var(--ec-tabs-active-color);
  border-color: var(--ec-tabs-active-color);
}

/* ---- Active bar (line type) ---- */
.ec-tabs__active-bar {
  display: none;
}

/* ---- Content ---- */
.ec-tabs__content {
  position: relative;
  overflow: hidden;
}

.ec-tabs__pane {
  outline: none;
}

/* ---- Line type ---- */
.ec-tabs--line > .ec-tabs__header {
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
  margin-bottom: 15px;
}

.ec-tabs--line .ec-tabs__active-bar {
  display: block;
  position: absolute;
  bottom: 0;
  left: 0;
  height: 2px;
  background-color: var(--ec-tabs-active-color);
  transition: var(--ec-transition-all);
}

/* Underline is rendered per-item so it tracks the active tab without JS measuring. */
.ec-tabs--line .ec-tabs__item {
  position: relative;
}

.ec-tabs--line .ec-tabs__item.is-active::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: -1px;
  height: 2px;
  background-color: var(--ec-tabs-active-color);
}

/* ---- Card type ---- */
.ec-tabs--card > .ec-tabs__header {
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
}

.ec-tabs--card .ec-tabs__nav {
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
  border-bottom: none;
  border-radius: var(--ec-border-radius-base) var(--ec-border-radius-base) 0 0;
}

.ec-tabs--card .ec-tabs__item {
  height: var(--ec-tabs-header-height);
  border-left: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
  background-color: var(--ec-fill-color-light);
  transition: var(--ec-transition-color);
}

.ec-tabs--card .ec-tabs__item:first-child {
  border-left: none;
}

.ec-tabs--card .ec-tabs__item.is-active {
  background-color: var(--ec-bg-color);
}

/* ---- Border-card type ---- */
.ec-tabs--border-card {
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color);
  border-radius: var(--ec-border-radius-base);
  background-color: var(--ec-bg-color);
  box-shadow: var(--ec-box-shadow-light);
}

.ec-tabs--border-card > .ec-tabs__header {
  margin: 0;
  background-color: var(--ec-fill-color-light);
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color);
}

.ec-tabs--border-card .ec-tabs__item {
  border-right: var(--ec-border-width) var(--ec-border-style) transparent;
  border-left: var(--ec-border-width) var(--ec-border-style) transparent;
  color: var(--ec-text-color-secondary);
  margin-top: -1px;
}

.ec-tabs--border-card .ec-tabs__item.is-active {
  color: var(--ec-tabs-active-color);
  background-color: var(--ec-bg-color);
  border-right-color: var(--ec-border-color);
  border-left-color: var(--ec-border-color);
}

.ec-tabs--border-card > .ec-tabs__content {
  padding: 15px;
}

/* ---- Stretch ---- */
.ec-tabs.is-stretch .ec-tabs__nav {
  width: 100%;
}

.ec-tabs.is-stretch .ec-tabs__item {
  flex: 1;
  justify-content: center;
}

/* ---- Tab positions ---- */
.ec-tabs--position-bottom {
  display: flex;
  flex-direction: column;
}

.ec-tabs--position-bottom > .ec-tabs__header {
  order: 2;
  margin: 15px 0 0;
}

.ec-tabs--position-bottom.ec-tabs--line > .ec-tabs__header {
  border-bottom: none;
  border-top: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
}

.ec-tabs--position-bottom.ec-tabs--line .ec-tabs__item.is-active::after {
  bottom: auto;
  top: -1px;
}

.ec-tabs--position-left,
.ec-tabs--position-right {
  display: flex;
}

.ec-tabs--position-left > .ec-tabs__header,
.ec-tabs--position-right > .ec-tabs__header {
  flex-direction: column;
  align-items: stretch;
  margin: 0;
}

.ec-tabs--position-left > .ec-tabs__header > .ec-tabs__nav,
.ec-tabs--position-right > .ec-tabs__header > .ec-tabs__nav {
  flex-direction: column;
  flex: 0 0 auto;
}

.ec-tabs--position-left > .ec-tabs__content,
.ec-tabs--position-right > .ec-tabs__content {
  flex: 1;
  padding: 0 15px;
}

.ec-tabs--position-right {
  flex-direction: row-reverse;
}

.ec-tabs--position-left.ec-tabs--line > .ec-tabs__header {
  border-bottom: none;
  border-right: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
}

.ec-tabs--position-right.ec-tabs--line > .ec-tabs__header {
  border-bottom: none;
  border-left: var(--ec-border-width) var(--ec-border-style) var(--ec-tabs-border-color);
}

.ec-tabs--position-left.ec-tabs--line .ec-tabs__item.is-active::after {
  left: auto;
  right: -1px;
  top: 0;
  bottom: 0;
  width: 2px;
  height: auto;
}

